    def chaos(self):
        hp = 300
        rounds = 0
        while hp > 0:
            input("Press enter to continue\n>")
            rounds += 1
            thing = self.choice(self.things)
            print(thing.replace('. ', '.\n'))
            change = re.sub(r'\[|\]', "", str(re.findall(r'[+-]\d+', thing)))
            change = change[:2] + '=' + change[2:]
            exec("hp"+re.sub("'", "", change))
            print(f"Health: {hp}")
        print("You died...")
        print(f"But survived {rounds - 1} rounds!")
